// @ts-nocheck
// Prism grammar definition for markdown — no imports from tokenize/grammar-loader
// to avoid circular dependency with languages/index.ts.
export default {
  language: 'markdown',
  init: (Prism: any) => {
    Prism.languages.markdown = Prism.languages.extend('markup', {})
    Prism.languages.insertBefore('markdown', 'prolog', {
      blockquote: {
        pattern: /^>(?:[\t ]*>)*/m,
        alias: 'punctuation',
      },
      code: [
        {
          pattern: /^(?: {4}|\t).+/m,
          alias: 'keyword',
        },
        {
          pattern: /``.+?``|`[^`\n]+`/,
          alias: 'keyword',
        },
      ],
      title: [
        {
          pattern: /\w+.*(?:\r?\n|\r)(?:==+|--+)/,
          alias: 'important',
          inside: {
            punctuation: /==+$|--+$/,
          },
        },
        {
          pattern: /(^\s*)#+.+/m,
          lookbehind: true,
          alias: 'important',
          inside: {
            punctuation: /^#+|#+$/,
          },
        },
      ],
      hr: {
        pattern: /(^\s*)([*-])(?:[\t ]*\2){2,}(?=\s*$)/m,
        lookbehind: true,
        alias: 'punctuation',
      },
      list: {
        pattern: /(^\s*)(?:[*+-]|\d+\.)(?=[\t ].)/m,
        lookbehind: true,
        alias: 'punctuation',
      },
      'url-reference': {
        pattern: /!?\[[^\]]+\]:[\t ]+(?:\S+|<(?:\\.|[^>\\])+>)(?:[\t ]+(?:"(?:\\.|[^"\\])*"|'(?:\\.|[^'\\])*'|\((?:\\.|[^)\\])*\)))?/,
        inside: {
          variable: {
            pattern: /^(!?\[)[^\]]+/,
            lookbehind: true,
          },
          string: /(?:"(?:\\.|[^"\\])*"|'(?:\\.|[^'\\])*'|\((?:\\.|[^)\\])*\))$/,
          punctuation: /^[\[\]!:]|[<>]/,
        },
        alias: 'url',
      },
      bold: {
        pattern: /(^|[^\\])(\*\*|__)(?:(?:\r?\n|\r)(?!\r?\n|\r)|.)+?\2/,
        lookbehind: true,
        inside: {
          punctuation: /^\*\*|^__|\*\*$|__$/,
        },
      },
      italic: {
        pattern: /(^|[^\\])([*_])(?:(?:\r?\n|\r)(?!\r?\n|\r)|.)+?\2/,
        lookbehind: true,
        inside: {
          punctuation: /^[*_]|[*_]$/,
        },
      },
      url: {
        pattern: /!?\[[^\]]+\](?:\([^\s)]+(?:[\t ]+"(?:\\.|[^"\\])*")?\)| ?\[[^\]\n]*\])/,
        inside: {
          variable: {
            pattern: /(!?\[)[^\]]+(?=\]$)/,
            lookbehind: true,
          },
          string: {
            pattern: /"(?:\\.|[^"\\])*"(?=\)$)/,
          },
        },
      },
    })

    Prism.languages.markdown.bold.inside.url = Prism.languages.markdown.url
    Prism.languages.markdown.italic.inside.url = Prism.languages.markdown.url
    Prism.languages.markdown.bold.inside.italic = Prism.languages.markdown.italic
    Prism.languages.markdown.italic.inside.bold = Prism.languages.markdown.bold
  },
}
